def detect_cascading_failure(response):
    if not response.stop_reason == 'tool_use':
        return False

    tools = response.content
    for i, block in enumerate(tools):
        if hasattr(block, 'type') and block.type == 'tool_use':
            tool_result = client.messages.create(
                model='claude-3-5-sonnet-20240620',
                messages=[{'role': 'assistant', 'content': [{'type': 'tool_result', 'tool_use_id': block.id, 'content': tool_result}]}],
                tools=[block.tools[0]]
            )
            if tool_result.content[0].type == 'tool_result' and tool_result.content[0].is_error:
                # Check if subsequent tools exist
                return i < len(tools) - 1
    return False

def detect_parallel_conflicts(response):
    tool_uses = [c for c in response.content if c.type == 'tool_use']
    if len(tool_uses) < 2:
        return False

    tool_names = [tu.name for tu in tool_uses]
    conflict_pairs = [
        ('price', 'inventory'),
        ('auth', 'permissions'),
        ('user', 'admin')
    ]

    for pair in conflict_pairs:
        if pair[0] in tool_names and pair[1] in tool_names:
            return True
    return False

