def arbitrate_tool_results(tools):
    results = {}
    for tool_result in tools:
        tool_name = tool_result.tool_use_id.split('_')[0]
        results[tool_name] = tool_result.content[0].content[0].text

    # Priority resolution for conflicts
    priority = {'inventory': 1, 'price': 2, 'auth': 3}
    resolved = {}
    for tool, result in results.items():
        if tool not in resolved or priority.get(tool, 99) < priority.get(list(resolved.keys())[0], 99):
            resolved[tool] = result

    return list(resolved.values())

SAFE_ELEMENTS = ['button#cancel', 'button.close', 'input.search']
BLOCKED_ELEMENTS = ['button#delete-all', 'button.confirm-destroy']

def safe_computer_use(response):
    for content in response.content:
        if content.type == 'tool_use' and content.name == 'computer_use':
            selector = content.input.get('selector', '')
            if any(blocked in selector for blocked in BLOCKED_ELEMENTS):
                return {'type': 'text', 'text': 'Blocked dangerous element interaction'}
            if not any(safe in selector for safe in SAFE_ELEMENTS):
                return {'type': 'text', 'text': 'Unrecognized safe element, aborting'}
    return response
